var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"참 희한하네요. 시간은 아침인데 아직도 달이 떠 있다니.","JPN":"珍しいですね。もう朝なのに月が見えます。","ENG":"That’s weird. It’s morning, and the moon is still there.","TWN":"真稀奇，明明是早上，卻還看得到月亮。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"그래. 세상이 망하려는 징조겠지.","JPN":"そうだな。この世の終わりの兆しだろう。","ENG":"Yes, it must be a sign that the world is coming to an end.","TWN":"是啊。這是世界末日的徵兆吧？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"하아, 가족들과 함께 있어도 아쉬울 때에 감옥이나 지키고 있어야 하다니. 내 팔자야.","JPN":"はあ、こんな時だからこそ家族と一緒にいたいのに、牢屋を見張ってないといけないとは。最悪だな。","ENG":"*Sigh* I’m supposed to be with my family, but here I am, guarding this prison cell.","TWN":"哀哀，明明應該要把握時間跟家人在一起，但我卻只能守著這個監牢，我還真命苦！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"재수없는 소리 좀 하지 마세요.","JPN":"縁起でもないことを言わないでください。","ENG":"Stop being so ominous.","TWN":"別說這種不吉利的話。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"연합이 어떻게든 해결할 겁니다. 옛 선조들이 그래왔던 것처럼요.","JPN":"連合がなんとか解決しますよ。ご先祖様がそうしてきたように。","ENG":"The Alliance will handle it. Like our ancestors did.","TWN":"聯盟無論如何都會解決的。就像以前祖先們那樣。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"흥. 3년 전 추방계획 때도 다들 그럴 거라고 믿었어.","JPN":"フン、3年前の追放計画の時もみんなそう信じて疑わなかったんだ。","ENG":"Hmpf. That’s what everyone said three years ago.","TWN":"哼，3年前驅逐計劃的時候，大家也都深信不疑。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"나나하라 당주 말만 듣고 오로치를 추방하려 했다가 봉인이 약해지는 바람에 거의 전멸할 뻔했지.","JPN":"七原家当主の言葉を信じてオロチを追放しようとしたが、\\n封印が弱まったせいで全滅寸前だったんだぞ。","ENG":"They went to purge Orochi on Lady Nanahara’s say-so, and they were all but wiped out due to the weakened seal.","TWN":"聽了七原堂主的話想要驅逐大蛇，結果封印變弱，搞得差點全軍覆沒。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"그 사건 때 죽은 당주들 자리엔 죄다 풋내기들뿐이야.","JPN":"あの事件で命を落とした当主の後任は、みんな青臭いヤツばかりだ。","ENG":"So many family leaders died on that day, and all we have left is their cubs.","TWN":"在那次事件中死去堂主的位子，全都是初出茅廬的傢伙接任的。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"제대로 배운 것 하나 없이, 책임만 물려받은 꼬맹이들이라고.","JPN":"まともな修行もできずに責任だけを押し付けられたガキどもなんだよ。","ENG":"Kids who inherited the responsibility without any proper education.","TWN":"他們什麼都沒學到，只有繼承責任。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"그 치들도 딱하죠. 어린 것들에게 무슨 잘못이 있겠습니까.","JPN":"気の毒ですね。まだ子どもだというのに。","ENG":"I feel sorry for them. They are still children who need care and support.","TWN":"他們也很可憐，孩子有什麼錯呢？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"정신 차려. 연민이 밥 먹여주나?","JPN":"何言ってんだよ、哀れむ必要なんかない！","ENG":"Wake up. Sympathy won’t save your butt.","TWN":"你清醒一點，同情能當飯吃嗎？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"오로치가 깨어나기라도 해 봐. 그 꼬마들만 남겨 두고 우린 전부 죽을걸.","JPN":"オロチが目を覚ましてみろ。\\nそいつらだけ残して俺たちは皆殺しだぞ。","ENG":"What if Orochi wakes up? Everyone will die except for those kids.","TWN":"等大蛇醒過來，只會留下那些小鬼，我們全都會沒命的。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"그렇다고는 해도…… 음?","JPN":"それはそうですが……あれ？","ENG":"But still—huh?","TWN":"就算是這樣……嗯？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"저, 저기! 창고 위로 솟구치는 저거! 불 아닙니까?!","JPN":"あ、あそこ！　倉庫の屋根から出てるあれ！　火じゃないですか！？","ENG":"L-look at the warehouse! It’s on fire!","TWN":"那…那個！竄到倉庫上面的是什麼！是火舌嗎？！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"뭐? 폭발도 없었는데 갑자기 무슨 화재야?","JPN":"え？　爆発音もなかったのに急に火災だと？","ENG":"What? I didn’t hear an explosion. Where did that come from?","TWN":"什麼？又沒有爆炸，怎麼會突然著火？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"소화 장치는 고장난 건가? 당장 소화기부터 찾아!","JPN":"消火装置は故障でもしたのか？　急いで消火器を持って来い！","ENG":"What happened to the automatic sprinkler system? Find a fire extinguisher! Quick!","TWN":"滅火器故障了嗎？趕快先找滅火器吧！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗. 멋지게 시선을 끌었군.","JPN":"フッ、最高のおとりになったな。","ENG":"Hah, they are all distracted.","TWN":"嘿嘿，調虎離山之計成功！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};